import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface Summary {
  totalPasswords: number;
  weakPasswords: number;
  reusedPasswords: number;
  securityScore: number;
}

interface PasswordDetails {
  category: string;
  count: number;
}

interface PasswordData {
  summary: Summary;
  passwordDetails: PasswordDetails[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const passwordData = response.data as PasswordData;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: metaData.primaryColor }}>
              Password Health
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mb: 1 }}>
              Security Score: {passwordData.summary.securityScore}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 120 }}>
            <PieChart
              height={120}
              series={[
                {
                  data: passwordData.passwordDetails.map((detail) => ({
                    label: detail.category,
                    value: detail.count,
                  })),
                  color: [metaData.primaryColor, metaData.accentColor, '#4FC3F7'],
                },
              ]}
              sx={{
                '& .MuiPieArc-root': {
                  stroke: '#1E1E1E',
                  strokeWidth: 2,
                },
              }}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            />
          </Box>

          <Stack direction="row" spacing={1.5} justifyContent="space-between">
            {passwordData.passwordDetails.map((detail, index) => (
              <Chip
                key={index}
                label={`${detail.category}: ${detail.count}`}
                sx={{ bgcolor: metaData.primaryColor, color: '#FFFFFF', fontSize: '11px' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
